patches.fixed_method:
private void normalise(Element element) {
    for (int i = 0; i < element.childNodes.size(); i++) {
        Node current = element.childNode(i);
        if (current instanceof TextNode) {
            TextNode textNode = (TextNode) current;
            if (textNode.isBlank()) {
                element.removeChild(current);
                i--; // Adjust index after removal
            } else {
                // Collapse adjacent text nodes
                StringBuilder sb = new StringBuilder();
                sb.append(textNode.text());

                Node next = textNode.nextSibling();
                while (next instanceof TextNode) {
                    TextNode nextTextNode = (TextNode) next;
                    sb.append(nextTextNode.text());
                    element.removeChild(next);
                    next = textNode.nextSibling();
                }
                textNode.text(sb.toString());
            }
        } else if (current instanceof Element) {
            normalise((Element) current);
        }
    }
}

private void normalise(Element element) {
    List<Node> toRemove = new ArrayList<Node>();
    for (Node node : element.childNodes) {
        if (node instanceof TextNode) {
            TextNode tn = (TextNode) node;
            if (tn.isBlank()) {
                toRemove.add(tn);
            }
        } else if (node instanceof Element) {
            // Recursively normalize child elements
            normalise((Element) node);
        }
    }

    // Remove all blank text nodes from the current element
    for (Node node : toRemove) {
        element.removeChild(node);
    }
}
